class Solution {
    public int maxConsecutiveAnswers(String answerKey, int k) {
        int maxCount = 0;
        int countT = maxConsecutive(answerKey, 'T', k);
        int countF = maxConsecutive(answerKey, 'F', k);
        return Math.max(countT, countF);
    }

    private int maxConsecutive(String answerKey, char target, int k) {
        int left = 0;
        int maxLen = 0;
        int count = 0;
        for (int right = 0; right < answerKey.length(); right++) {
            if (answerKey.charAt(right) != target) {
                count++;
            }
            while (count > k) {
                if (answerKey.charAt(left) != target) {
                    count--;
                }
                left++;
            }
            maxLen = Math.max(maxLen, right - left + 1);
        }
        return maxLen;
    }
}
